  ('promotion-a26c2ed9-moex-00035', 'promotion-a26c2ed9', 'promotion-a26c2ed9-moex-112-3082b5f1', 'sub-promotion-a26c2ed9-02', NULL, 'essay', '衛生福利部為有效執行食品安全衛生管理法第 28 條第 1 項、第 2 項禁
止食品標示、宣傳或廣告不實、誇張、易生誤解或宣稱醫療效能之規定，
依同法第28 條第 4 項規定：「第一項不實、誇張或易生誤解與第二項醫
療效能之認定基準、宣傳或廣告之內容、方式及其他應遵行事項之準則，
由中央主管機關定之。」所訂定之「食品及相關產品標示宣傳廣告涉及
不實誇張易生誤解或醫療效能認定準則」，請說明本準則之法律性質、意
涵及效力。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:19+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "145", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "安全保防"}'::jsonb, NULL),
  ('promotion-a26c2ed9-moex-00036', 'promotion-a26c2ed9', 'promotion-a26c2ed9-moex-112-3082b5f1', 'sub-promotion-a26c2ed9-02', NULL, 'single_choice', '關於行政法規新舊法適用，下列敘述何者錯誤？', '["人民聲請許可案件處理程序終結前，據以准許之法規變更者，原則上適用新法規", "人民聲請許可案件處理程序終結前，舊法規有利於當事人而新法規未廢除或禁止所聲請之事項 者，適用舊法規", "新修正之普通法應優先於舊的特別法適用", "違法行為後、裁處前法律變更，適用最有利於受處罰者之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:19+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "145", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "安全保防"}'::jsonb, NULL),
